parameters.jsCode:
// Code node to combine Fathom transcript segments
// Place this node immediately after your Fathom webhook

// The webhook data comes in as $json.body
// The transcript array is at $json.body.transcript

const transcriptArray = $json.body.transcript || [];

// Combine all transcript segments into one continuous text
const fullTranscript = transcriptArray
  .map(segment => segment.text)
  .filter(text => text) // Remove any empty segments
  .join(' ');

// Optional: Also create a formatted version with speaker names and timestamps
const formattedTranscript = transcriptArray
  .map(segment => {
    const speaker = segment.speaker?.display_name || 'Unknown';
    const text = segment.text || '';
    const timestamp = segment.timestamp || '';
    return `[${timestamp}] ${speaker}: ${text}`;
  })
  .join('\n');

// Return both versions so you can use whichever you prefer
return {
  json: {
    fullTranscript: fullTranscript,
    formattedTranscript: formattedTranscript,
    transcriptLength: fullTranscript.length,
    segmentCount: transcriptArray.length
  }
};

