parameters.jsCode:
// Get the summary text
const summaryText = $input.first().json.output;

// Split into chunks of 2000 characters
const chunkSize = 2000;
const chunks = [];

for (let i = 0; i < summaryText.length; i += chunkSize) {
  chunks.push(summaryText.substring(i, i + chunkSize));
}

// Format for Notion blocks
const blocks = chunks.map(chunk => ({
  type: "paragraph",
  paragraph: {
    rich_text: [{
      type: "text",
      text: { content: chunk }
    }]
  }
}));

return [{ json: { blocks } }];

